// Validate incoming request
const body = $input.first().json.body;

if (!body.user_id || !body.file_type) {
  throw new Error('Missing required fields: user_id, file_type');
}

const fileId = body.file_id || `file_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

return [{
  json: {
    user_id: body.user_id,
    file_id: fileId,
    file_name: body.file_name || 'Untitled',
    file_type: body.file_type,       // 'pdf', 'youtube', 'rss', 'web'
    source_url: body.source_url || '',
    content: body.content || '',      // pre-extracted text (optional)
    metadata: body.metadata || {}
  }
}];

// PDF Text Extraction
// If content was pre-extracted by the frontend, use it directly.
// Otherwise, attempt to fetch and do basic text extraction.
const item = $input.first().json;

let extractedText = '';

if (item.content && item.content.trim().length > 0) {
  // Pre-extracted text provided by frontend
  extractedText = item.content;
} else if (item.source_url) {
  // For PDF URLs, we note that full PDF parsing typically
  // requires a dedicated service. Here we provide a fallback.
  extractedText = `[PDF content from: ${item.source_url}] — ` +
    'For production, integrate a PDF parsing service like ' +
    'pdf-parse, Apache Tika, or use the n8n Extract From File node.';
} else {
  throw new Error('No content or source_url provided for PDF processing');
}

return [{
  json: {
    ...item,
    extracted_text: extractedText,
    extraction_method: 'pdf'
  }
}];

// YouTube Transcript Extraction via yt-dlp
// This node prepares the command. The actual execution
// happens in the next Execute Command node.
const item = $input.first().json;

if (!item.source_url) {
  throw new Error('No YouTube URL provided in source_url');
}

// Extract video ID from URL
const url = item.source_url;
let videoId = '';
if (url.includes('youtu.be/')) {
  videoId = url.split('youtu.be/')[1].split('?')[0];
} else if (url.includes('watch?v=')) {
  videoId = url.split('watch?v=')[1].split('&')[0];
} else {
  videoId = url;
}

return [{
  json: {
    ...item,
    video_id: videoId,
    yt_command: `yt-dlp --write-auto-sub --sub-lang en --skip-download --print-to-file "%(subtitles.en.-1.ext)s" - "${url}" 2>/dev/null || yt-dlp --write-auto-sub --sub-lang en --skip-download -o - "${url}" 2>&1 | grep -v "^\[" | head -500`
  }
}];

// Process yt-dlp output into clean transcript text
const item = $input.first().json;
const rawOutput = item.stdout || item.stderr || '';

// Clean yt-dlp subtitle output — remove timestamps and formatting
let transcript = rawOutput
  .split('\n')
  .filter(line => {
    // Skip timestamp lines, empty lines, and yt-dlp info lines
    return line.trim().length > 0 &&
      !line.match(/^\d{2}:\d{2}/) &&
      !line.match(/^\[/) &&
      !line.includes('-->') &&
      !line.match(/^<\/?c>/) &&
      !line.match(/^WEBVTT/);
  })
  .map(line => line.replace(/<[^>]+>/g, '').trim())
  .filter(line => line.length > 0)
  .join(' ');

// Deduplicate repeated phrases (common in auto-generated subs)
const words = transcript.split(' ');
const deduped = [];
for (let i = 0; i < words.length; i++) {
  if (i === 0 || words[i] !== words[i-1]) {
    deduped.push(words[i]);
  }
}
transcript = deduped.join(' ');

if (transcript.length < 50) {
  transcript = 'Transcript extraction failed or video has no captions. Raw output: ' + rawOutput.substring(0, 500);
}

// Get metadata from the previous prepare node
const prevData = $('Prepare: YouTube CMD').first().json;

return [{
  json: {
    user_id: prevData.user_id,
    file_id: prevData.file_id,
    file_name: prevData.file_name,
    file_type: prevData.file_type,
    source_url: prevData.source_url,
    metadata: prevData.metadata,
    extracted_text: transcript,
    extraction_method: 'youtube_yt-dlp'
  }
}];

// Parse RSS/Atom feed content and extract text
const item = $input.first().json;
const prevData = $('Switch: File Type').first().json;
const rawXml = typeof item.data === 'string' ? item.data : JSON.stringify(item);

// Basic RSS/Atom text extraction
let articles = [];

// Extract items from RSS
const itemMatches = rawXml.match(/<item[^>]*>[\s\S]*?<\/item>/gi) || 
                   rawXml.match(/<entry[^>]*>[\s\S]*?<\/entry>/gi) || [];

for (const entry of itemMatches) {
  const titleMatch = entry.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  const descMatch = entry.match(/<description[^>]*>([\s\S]*?)<\/description>/i) ||
                   entry.match(/<content[^>]*>([\s\S]*?)<\/content>/i) ||
                   entry.match(/<summary[^>]*>([\s\S]*?)<\/summary>/i);

  const title = titleMatch ? titleMatch[1].replace(/<[^>]+>/g, '').replace(/<!\[CDATA\[|\]\]>/g, '').trim() : '';
  const desc = descMatch ? descMatch[1].replace(/<[^>]+>/g, '').replace(/<!\[CDATA\[|\]\]>/g, '').trim() : '';

  if (title || desc) {
    articles.push(`## ${title}\n${desc}`);
  }
}

const extractedText = articles.length > 0 
  ? articles.join('\n\n---\n\n') 
  : rawXml.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 10000);

return [{
  json: {
    user_id: prevData.user_id,
    file_id: prevData.file_id,
    file_name: prevData.file_name,
    file_type: prevData.file_type,
    source_url: prevData.source_url,
    metadata: { ...prevData.metadata, article_count: articles.length },
    extracted_text: extractedText,
    extraction_method: 'rss_feed'
  }
}];

// Extract readable text from HTML web page
const item = $input.first().json;
const prevData = $('Switch: File Type').first().json;
const html = typeof item.data === 'string' ? item.data : JSON.stringify(item);

// Remove script, style, nav, footer, header tags
let text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '')
  .replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '')
  .replace(/<aside[^>]*>[\s\S]*?<\/aside>/gi, '');

// Convert block elements to newlines
text = text
  .replace(/<\/?(p|div|br|h[1-6]|li|tr|td|th|blockquote|pre)[^>]*>/gi, '\n')
  .replace(/<[^>]+>/g, ' ')               // Remove remaining tags
  .replace(/&nbsp;/g, ' ')                // Fix entities
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/\s+/g, ' ')                   // Collapse whitespace
  .trim();

// Get the meaningful content (skip very short results)
if (text.length < 100) {
  text = 'Web content extraction returned minimal text. The page may require JavaScript rendering.';
}

return [{
  json: {
    user_id: prevData.user_id,
    file_id: prevData.file_id,
    file_name: prevData.file_name,
    file_type: prevData.file_type,
    source_url: prevData.source_url,
    metadata: prevData.metadata,
    extracted_text: text.substring(0, 50000),  // Cap at 50k chars
    extraction_method: 'web_scrape'
  }
}];

// Chunk text with overlap for embedding
const item = $input.first().json;
const text = item.extracted_text || '';
const CHUNK_SIZE = 800;       // ~800 chars per chunk
const CHUNK_OVERLAP = 150;    // 150 char overlap for context

if (text.length === 0) {
  throw new Error('No text to chunk');
}

const chunks = [];
let currentIndex = 0;

while (currentIndex < text.length) {
  let endIndex = currentIndex + CHUNK_SIZE;

  // Find word boundary
  if (endIndex < text.length) {
    const lastSpace = text.lastIndexOf(' ', endIndex);
    if (lastSpace > currentIndex) {
      endIndex = lastSpace;
    }
  } else {
    endIndex = text.length;
  }

  const chunkContent = text.slice(currentIndex, endIndex).trim();

  if (chunkContent.length > 20) {  // Skip tiny chunks
    chunks.push({
      json: {
        user_id: item.user_id,
        file_id: item.file_id,
        file_name: item.file_name,
        file_type: item.file_type,
        chunk_index: chunks.length,
        content: chunkContent,
        metadata: {
          ...item.metadata,
          extraction_method: item.extraction_method,
          source_url: item.source_url || null,
          total_chars: text.length,
          chunk_start: currentIndex,
          chunk_end: endIndex
        }
      }
    });
  }

  currentIndex = endIndex - CHUNK_OVERLAP;
  if (currentIndex <= (endIndex - CHUNK_SIZE)) {
    currentIndex = endIndex;
  }
}

console.log(`Created ${chunks.length} chunks from ${text.length} characters`);
return chunks;

// Prepare data for Supabase insertion
const items = $input.all();
const results = [];

for (const item of items) {
  const embedding = item.json.data || item.json;

  // The HuggingFace feature-extraction endpoint returns
  // the embedding as a nested array. We need the first element.
  let embeddingVector;
  if (Array.isArray(embedding) && Array.isArray(embedding[0])) {
    embeddingVector = embedding[0]; // sentence-level embedding
  } else if (Array.isArray(embedding)) {
    embeddingVector = embedding;
  } else {
    throw new Error('Unexpected embedding format: ' + JSON.stringify(embedding).substring(0, 200));
  }

  // Get the original chunk data from the Chunk node
  // We use the item index to match
  const chunkData = $('Chunk: Split Text').all();
  const idx = items.indexOf(item);
  const chunk = chunkData[idx]?.json || {};

  results.push({
    json: {
      user_id: chunk.user_id,
      file_id: chunk.file_id,
      file_name: chunk.file_name,
      file_type: chunk.file_type,
      chunk_index: chunk.chunk_index,
      content: chunk.content,
      metadata: chunk.metadata || {},
      embedding: `[${embeddingVector.join(',')}]`  // pgvector format
    }
  });
}

return results;

// Summarize results
const stored = $input.all();
const firstChunk = $('Chunk: Split Text').first().json;

return [{
  json: {
    success: true,
    message: `Successfully processed and stored ${stored.length} chunks`,
    file_id: firstChunk.file_id,
    file_name: firstChunk.file_name,
    file_type: firstChunk.file_type,
    chunks_stored: stored.length,
    timestamp: new Date().toISOString()
  }
}];

// Error handler — catch and format errors
const error = $input.first().json;

return [{
  json: {
    success: false,
    error: error.message || 'An unknown error occurred during file processing',
    timestamp: new Date().toISOString()
  }
}];
